if (programText == null) return null
def text = programText.toString().trim()
if (text.isEmpty()) return null

// Quitar prefijo "EP " que usa Oracle LAMB en ESCUELA_PROFESIONAL y NOMBRE_ESCUELA
def cleanText = text.replaceFirst(/(?i)^EP\s+/, '').trim()

def tableOid = 'd9b1e0c2-e036-4c6a-9753-c732a83bbf0a'

try {
    def options = com.evolveum.midpoint.schema.SelectorOptions.createCollection(
        com.evolveum.midpoint.prism.path.ItemPath.create(com.evolveum.midpoint.xml.ns._public.common.common_3.LookupTableType.F_ROW),
        com.evolveum.midpoint.schema.GetOperationOptions.createRetrieve()
    )
    def tableObj = midpoint.getObject(com.evolveum.midpoint.xml.ns._public.common.common_3.LookupTableType.class, tableOid, options)
    if (tableObj == null) {
        log.warn('sb-program-resolver: LookupTable {} not found', tableOid)
        return null
    }
    def rows = tableObj.getRow()
    if (rows == null || rows.isEmpty()) {
        log.warn('sb-program-resolver: LookupTable {} has no rows', tableOid)
        return null
    }

    // Pass 1: exact case-insensitive match (texto limpio)
    for (def row : rows) {
        if (row.getKey() != null && row.getKey().equalsIgnoreCase(cleanText)) {
            return row.getValue()
        }
    }

    // Pass 2: normalized match (lowercase, no accents, single spaces)
    def normalize = { String s ->
        if (s == null) return ''
        def n = java.text.Normalizer.normalize(s.toLowerCase().trim(), java.text.Normalizer.Form.NFD)
        n = n.replaceAll('\\p{InCombiningDiacriticalMarks}+', '')
        n = n.replaceAll('\\s+', ' ')
        return n
    }
    def normText = normalize(cleanText)
    for (def row : rows) {
        if (normalize(row.getKey()) == normText) {
            return row.getValue()
        }
    }

    log.debug('sb-program-resolver: no match for "{}" (cleaned: "{}")', text, cleanText)
    return null
} catch (Exception e) {
    log.warn('sb-program-resolver: error resolving "{}": {}', text, e.getMessage())
    return null
}

if (programText == null) return null
def text = programText.toString().trim()
if (text.isEmpty()) return null

def cleanText = text.replaceFirst(/(?i)^EP\s+/, '').trim()

def tableOid = 'd9b1e0c2-e036-4c6a-9753-c732a83bbf0a'

try {
    def options = com.evolveum.midpoint.schema.SelectorOptions.createCollection(
        com.evolveum.midpoint.prism.path.ItemPath.create(com.evolveum.midpoint.xml.ns._public.common.common_3.LookupTableType.F_ROW),
        com.evolveum.midpoint.schema.GetOperationOptions.createRetrieve()
    )
    def tableObj = midpoint.getObject(com.evolveum.midpoint.xml.ns._public.common.common_3.LookupTableType.class, tableOid, options)
    if (tableObj == null) return null
    def rows = tableObj.getRow()
    if (rows == null) return null

    // Pass 1: exact case-insensitive
    for (def row : rows) {
        if (row.getKey() != null && row.getKey().equalsIgnoreCase(cleanText)) {
            def lab = row.getLabel()
            if (lab != null) return lab.getOrig()
            return null
        }
    }

    // Pass 2: normalized
    def normalize = { String s ->
        if (s == null) return ''
        def n = java.text.Normalizer.normalize(s.toLowerCase().trim(), java.text.Normalizer.Form.NFD)
        n = n.replaceAll('\\p{InCombiningDiacriticalMarks}+', '')
        n = n.replaceAll('\\s+', ' ')
        return n
    }
    def normText = normalize(cleanText)
    for (def row : rows) {
        if (normalize(row.getKey()) == normText) {
            def lab = row.getLabel()
            if (lab != null) return lab.getOrig()
            return null
        }
    }
    return null
} catch (Exception e) {
    log.warn('sb-program-resolver.resolveProgramCode: error "{}" -> {}', text, e.getMessage())
    return null
}
